import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"签证基础知识","description":"了解签证类型、申请流程和注意事项","frontmatter":{"title":"签证基础知识","description":"了解签证类型、申请流程和注意事项"},"headers":[],"relativePath":"knowledge/visa/basics.md","filePath":"knowledge/visa/basics.md","lastUpdated":null}'),i={name:"knowledge/visa/basics.md"};function s(l,a,n,d,c,h){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="签证基础知识" tabindex="-1">签证基础知识 <a class="header-anchor" href="#签证基础知识" aria-label="Permalink to &quot;签证基础知识&quot;">​</a></h1><h2 id="什么是签证" tabindex="-1">什么是签证 <a class="header-anchor" href="#什么是签证" aria-label="Permalink to &quot;什么是签证&quot;">​</a></h2><p>签证是主权国家颁发给外国公民的入境许可证明。它通常以贴纸或电子形式附在护照上，标明允许入境的期限和目的。</p><h2 id="常见签证类型" tabindex="-1">常见签证类型 <a class="header-anchor" href="#常见签证类型" aria-label="Permalink to &quot;常见签证类型&quot;">​</a></h2><p>旅游签证、商务签证、学生签证、工作签证和过境签证是最常见的类型。旅行者通常只需要申请旅游签证即可。</p><h2 id="签证申请基本流程" tabindex="-1">签证申请基本流程 <a class="header-anchor" href="#签证申请基本流程" aria-label="Permalink to &quot;签证申请基本流程&quot;">​</a></h2><p>一般流程包括：确定签证类型 → 准备材料 → 在线填写申请表 → 预约递交时间 → 递交材料和指纹 → 等待审核 → 领取护照。</p><h2 id="签证费用" tabindex="-1">签证费用 <a class="header-anchor" href="#签证费用" aria-label="Permalink to &quot;签证费用&quot;">​</a></h2><p>各国签证费用从免费到数百美元不等，通常与签证类型、处理速度和双边协议有关。</p>',9)])])}const u=e(i,[["render",s]]);export{_ as __pageData,u as default};
